package com.example.ui

import androidx.compose.ui.graphics.ImageBitmap
import androidx.compose.ui.graphics.asImageBitmap
import android.graphics.BitmapFactory
import android.util.Base64
import com.example.model.ChartBody

object IconAssets {
    private val base64Map = mapOf<ChartBody, String>(
        ChartBody.CERES to "",
        ChartBody.CHIRON to "",
        ChartBody.JUNO to "",
        ChartBody.JUPITER to "",
        ChartBody.LILITH to "",
        ChartBody.MARS to "",
        ChartBody.MERCURY to "",
        ChartBody.MOON to "",
        ChartBody.NEPTUNE to "",
        ChartBody.NORTH_NODE to "",
        ChartBody.SOUTH_NODE to "",
        ChartBody.PALLAS to "",
        ChartBody.PHOLUS to "",
        ChartBody.PLUTO to "",
        ChartBody.SATURN to "",
        ChartBody.SUN to "",
        ChartBody.URANUS to "",
        ChartBody.VENUS to "",
        ChartBody.VESTA to "",
    )

    private val bitmapCache = mutableMapOf<ChartBody, ImageBitmap>()

    fun getMarker(body: ChartBody): ImageBitmap? {
        if (bitmapCache.containsKey(body)) return bitmapCache[body]
        val b64 = base64Map[body] ?: return null
        val bytes = Base64.decode(b64, Base64.DEFAULT)
        val bitmap = BitmapFactory.decodeByteArray(bytes, 0, bytes.size).asImageBitmap()
        bitmapCache[body] = bitmap
        return bitmap
    }
}
